const [paginationByEntity, setPaginationByEntity] = useState({});

const updatePagination = useCallback((entityType, entityId, updates) => {
    const key = `${entityType}-${entityId}`;
    setPaginationByEntity(prev => ({
        ...prev,
        [key]: {
            ...prev[key],
            ...updates
        }
    }));
}, []);

