const handleLoadMore = async () => {
    try {
        const moreNotes = await handleFetchNotes('project', project.id, { append: true });
        if (moreNotes && moreNotes.length > 0) {
            setAllNotes(prev => [...prev, ...moreNotes]);
        }
    } catch (error) {
        console.error('Error loading more notes:', error); // No user feedback
    }
};

export function transformBackendNote(note) {
    if (!note) {
        return null;
    }

    return {
        id: note.id,
        content: note.note,
        // ...
        createdBy: note.created_by || null,
        updatedBy: note.updated_by || null,
        organizationId: note.organization_id, // No null coalescing
        projectId: note.project_id || null, // Inconsistent
        customerId: note.customer_id || null,
        taskId: note.task_id || null,
        // ...
    };
}
